@use '../abstracts'as *;


// FLEX BOX SYSTEM
// TAKEN FROM: https://www.youtube.com/watch?v=g1kF45K-q7o&t=1s
// A BIT OF SHAME IS THAT FOR NOW I AM USING A BORDER OF 7.5px of every side to do the spacing

.row {
    display: flex;
    flex-direction: row;
    justify-content: stretch;
    align-items: stretch;
    flex-wrap: wrap;

    &.column {
        flex-direction: column;
    }

    @include for-watches-only {
        flex-direction: column;
        padding: 0 $containerConstant - 2%;
    }

    @include for-phones-only {
        padding: 0 $containerConstant - 1.5%;
