            flex-direction: row-reverse;
        }
        &.column-reverse-mobile {
            flex-direction: column-reverse;
        }
    }

    @include for-tablets {
        padding: 0 $containerConstant - 1%;
        &.reverse {
            flex-direction: row-reverse;
        }
        &.column-reverse {
            flex-direction: column-reverse;
        }
    }

    @include for-laptops {
        padding: 0 $containerConstant - 0.60%;
    }

    &.h-center {
        justify-content: center;

        @include for-phones-only {
            align-items: center;
        }
    }

    &.v-center {
        align-items: center;

        @include for-phones-only {
            justify-content: center;
        }
    }
}

$columns: 3;

[class^=col-] {
    flex-basis: 100%;
    // SHAMEFUL USE OF BORDERS FOR THE GUTTERS
    border: (15px / 2) solid transparent;
    border-bottom: 0;
    border-top: 0;

    // background-color: $darkTurquoise;
    // padding: $smallSpace;
}

@include for-phones-only {
    @for $i from 1 through $columns {
        .col-m-#{$i} {
            flex: 0 0 (100% / ($columns /$i));
        }

        .col-m-offset-#{$i} {
            margin-left: 100% / ($columns*2 /$i);
            margin-right: 100% / ($columns*2 /$i);
        }

        .col-m-offset-left-#{$i} {
            margin-left: 100% / ($columns*2 /$i);
        }

        .col-m-offset-right-#{$i} {
            margin-right: 100% / ($columns*2 /$i);
        }
    }

    .col-m-half {
        flex: 0 0 50%;
    }
}



@include for-tablets {
    $columns: 6;

    @for $i from 1 through $columns {
        .col-t-#{$i} {
            flex: 0 0 (100% / ($columns /$i));

        }

        .col-t-offset-#{$i} {
            margin-left: 100% / ($columns*2 /$i);
            margin-right: 100% / ($columns*2 /$i);
        }

        .col-t-offset-left-#{$i} {
            margin-left: 100% / ($columns*2 /$i);
        }

        .col-t-offset-right-#{$i} {
            margin-left: 100% / ($columns*2 /$i);
        }
    }
}

@include for-laptops {
    $columns: 12;

    @for $i from 1 through $columns {
        .col-#{$i} {
            flex: 0 0 (100% / ($columns /$i));
        }

        .col-offset-#{$i} {
            margin-left: 100% / ($columns /$i);
            margin-right: 100% / ($columns /$i);
        }

        .col-offset-left-#{$i} {
            margin-left: 100% / ($columns /$i);

        }

        .col-offset-right-#{$i} {
            margin-right: 100% / ($columns /$i);
        }
    }
}

