    }

    &.big, > .big {
        font-size: 1.3rem;
    }
}

a {
    text-decoration: underline;
    color: $gray;

}


// TABLET

@include for-tablets {
    h1 {
        font-size: 2.3rem;
    }
}

// DESKTOP/ LAPTOPS
@include for-laptops {
    h1 {
        font-size: 2.5rem;
    }
}
